CREATE OR REPLACE FUNCTION public.update_sale(_sale_id uuid, _customer_id uuid, _sale_date date, _discount numeric, _paid numeric, _payment_method text, _sale_type text, _note text, _items jsonb, _installments integer, _installment_frequency text, _installment_start date) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE _sale RECORD; _shop_id UUID; _item JSONB; _subtotal NUMERIC := 0; _tax_total NUMERIC := 0; _item_disc_total NUMERIC := 0; _total NUMERIC; _due NUMERIC; _pid UUID; _qty NUMERIC; _price NUMERIC; _cost NUMERIC; _idisc NUMERIC; _trate NUMERIC; _tax NUMERIC; _line NUMERIC; _i INTEGER; _inst_amount NUMERIC; _inst_date DATE; _remaining NUMERIC; _final_paid NUMERIC; BEGIN IF _sale_type NOT IN ('cash','due','installment') THEN RAISE EXCEPTION 'invalid sale_type'; END IF; IF _sale_type IN ('due','installment') AND _customer_id IS NULL THEN RAISE EXCEPTION 'customer required for due/installment'; END IF; PERFORM public.update_sale_reverse(_sale_id); SELECT * INTO _sale FROM public.sales WHERE id = _sale_id; _shop_id := _sale.shop_id; FOR _item IN SELECT * FROM jsonb_array_elements(_items) LOOP _qty := (_item->>'quantity')::NUMERIC; _price := (_item->>'unit_price')::NUMERIC; _idisc := COALESCE(NULLIF(_item->>'discount_amount','')::NUMERIC, 0); _trate := COALESCE(NULLIF(_item->>'tax_rate','')::NUMERIC, 0); _line := (_qty * _price) - _idisc; _tax := ROUND(_line * _trate / 100.0, 2); _subtotal := _subtotal + (_qty * _price); _item_disc_total := _item_disc_total + _idisc; _tax_total := _tax_total + _tax; END LOOP; _total := _subtotal - _item_disc_total - COALESCE(_discount,0) + _tax_total; _final_paid := COALESCE(_paid, 0); IF _sale_type = 'cash' THEN _final_paid := _total; END IF; _due := GREATEST(_total - _final_paid, 0); UPDATE public.sales SET customer_id = _customer_id, sale_date = COALESCE(_sale_date, sale_date), subtotal = _subtotal, discount = COALESCE(_discount,0) + _item_disc_total, tax_amount = _tax_total, total = _total, paid = _final_paid, due = _due, sale_type = _sale_type, payment_method = COALESCE(_payment_method,'cash'), note = _note, status = 'completed', updated_at = now() WHERE id = _sale_id; FOR _item IN SELECT * FROM jsonb_array_elements(_items) LOOP _pid := (_item->>'product_id')::UUID; _qty := (_item->>'quantity')::NUMERIC; _price := (_item->>'unit_price')::NUMERIC; _cost := NULLIF(_item->>'unit_cost','')::NUMERIC; _idisc := COALESCE(NULLIF(_item->>'discount_amount','')::NUMERIC, 0); _trate := COALESCE(NULLIF(_item->>'tax_rate','')::NUMERIC, 0); _line := (_qty * _price) - _idisc; _tax := ROUND(_line * _trate / 100.0, 2); INSERT INTO public.sale_items(shop_id, sale_id, product_id, quantity, unit_price, unit_cost, line_total, discount_amount, tax_rate, tax_amount) VALUES (_shop_id, _sale_id, _pid, _qty, _price, _cost, _line + _tax, _idisc, _trate, _tax); PERFORM public.apply_stock_movement(_shop_id, _pid, 'sale', _qty, _cost, 'sale_edit', _sale_id, 'edit'); END LOOP; IF _customer_id IS NOT NULL AND _due > 0 THEN UPDATE public.customers SET current_balance = current_balance + _due WHERE id = _customer_id AND shop_id = _shop_id; END IF; IF _final_paid > 0 AND _customer_id IS NOT NULL THEN INSERT INTO public.customer_payments(shop_id, customer_id, sale_id, amount, payment_method, payment_date, note, created_by) VALUES (_shop_id, _customer_id, _sale_id, _final_paid, COALESCE(_payment_method,'cash'), COALESCE(_sale_date, CURRENT_DATE), 'edited sale payment', auth.uid()); END IF; IF _sale_type = 'installment' AND _installments IS NOT NULL AND _installments > 0 AND _due > 0 THEN _inst_amount := ROUND(_due / _installments, 2); _remaining := _due; FOR _i IN 1.._installments LOOP IF _i = _installments THEN _inst_amount := _remaining; END IF; IF _installment_frequency = 'weekly' THEN _inst_date := COALESCE(_installment_start, CURRENT_DATE) + (_i * INTERVAL '7 days'); ELSE _inst_date := COALESCE(_installment_start, CURRENT_DATE) + (_i * INTERVAL '1 month'); END IF; INSERT INTO public.installment_schedules(shop_id, sale_id, customer_id, installment_no, due_date, amount) VALUES (_shop_id, _sale_id, _customer_id, _i, _inst_date, _inst_amount); _remaining := _remaining - _inst_amount; END LOOP; END IF; RETURN _sale_id; END; $$;